messages.content:
CLUSTER:
[
 {
  "riskId": "risk.boundary-substitution.colo-spec-contagion-from-hyperscale-tenants",
  "title": "Wholesale colocation inherits hyperscaler power specs: the 18% colo slice — modeled with zero sensitivity band — follows the substitute out of category",
  "narrative": "The model treats colocation as the PDU-native safe harbor: seg.colocation carries a null sensitivity band, so it never appears in the tornado at all. But CBRE shows European colo take-up being outstripped by hyperscaler and AI/HPC tenant demand — and in wholesale/prelet halls the tenant, not the operator, dictates the rack power architecture. If hyperscale tenants specify busway plus power shelves inside leased halls (the same migration the exemplar tracks in self-build), the colo segment's PDU content leaves the category through the tenant spec sheet while the operator's capacity numbers keep growing 19% a year. The one segment the engine treats as certain is the one with the untracked contagion path.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "European colocation take-up is expected to outstrip new supply driven specifically by hyperscaler and AI/HPC tenants — the demand filling CE colo halls is the same buyer cohort migrating to busway/power-shelf architectures, and in wholesale preleases that tenant writes the fit-out power spec",
    "refs": [
     "digest:seg-mix#c15",
     "digest:seg-mix#c13"
    ]
   },
   {
    "step": "propagation",
    "text": "As hyperscale tenants standardize substitute architectures inside leased halls, colo PDU content per MW falls even as colo capacity grows near double-digit and supply across the top-5 markets grows a record 20% — capacity metrics stay healthy while category-specific demand erodes",
    "refs": [
     "digest:seg-mix#c18",
     "digest:seg-mix#c16"
    ]
   },
   {
    "step": "model-impact",
    "text": "seg.colocation 0.18 is single-source with a null band: the engine registers zero downside for this slice, so a tenant-spec-driven erosion of colo PDU demand is structurally invisible in every sensitivity output the client's team has reviewed",
    "refs": [
     "ledger:seg.colocation",
     "digest:seg-mix#c1"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Rack power architecture named in wholesale prelease fit-out specifications for AI-density halls",
    "where": "Frankfurt and Amsterdam wholesale colo prelease announcements and fit-out tender documents; DCD/DCNN build coverage",
    "threshold": "≥2 CE wholesale preleases specifying busway/power-shelf distribution as tenant standard",
    "updates": "increases"
   },
   {
    "signal": "Colo operator capex-call language on standardizing power distribution for AI halls",
    "where": "Digital Realty and Equinix EMEA quarterly capex calls and investor-day fit-out cost breakdowns",
    "threshold": "Explicit mention of busway or shelf standardization for new AI capacity",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17
 },
 {
  "riskId": "risk.structure-independence.ce-hyperscale-global-split-mirage",
  "title": "The DE×hyperscale anchor cell is a mirage: CE-7's hyperscale-owned share is far below the rescaled global 44%",
  "narrative": "seg.hyperscale rescales Synergy's global 48% flat onto Central Europe. But ~60% of Europe's operational hyperscaler self-build capacity sits in Ireland, the Netherlands, Sweden and Belgium — three of the four outside CE-7. Inside CE, hyperscale presence is mostly leased capacity inside Frankfurt and Amsterdam colo campuses, which Statista's 'colocation and scale colocation' figure already counts on the geography axis as colo MW. The cube therefore double-books the same megawatts — hyperscale on the segment axis, colo on the geo axis — and the implied beachhead cell (DE 0.50 × hyperscale 0.44 ≈ 22% of TAM as 'German hyperscale') largely does not exist as hyperscale-owned facilities. The real buyer of that capacity's PDUs is the colo operator or its integrator, with colo-grade requirements: tenant billing metering, multi-tenant DCIM. A product roadmap and sales motion built for hyperscale custom SKUs in Germany aims at a cell the market never populated.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Synergy's 48% hyperscale share is global; CBRE-sourced reporting places ~60% of Europe's operational hyperscaler self-build in Ireland, Netherlands, Sweden and Belgium — a geography that barely overlaps CE-7 — while the model applies the global split flat with a 0.91 carve-out",
    "refs": [
     "digest:seg-mix#c0",
     "digest:seg-mix#c14",
     "ledger:seg.hyperscale"
    ]
   },
   {
    "step": "propagation",
    "text": "Within CE-7, hyperscale demand is predominantly leased: European colocation remains significantly larger than self-build, FLAPD colo hubs (Frankfurt, Amsterdam in CE) absorb the hyperscale take-up, and the Statista geo denominator counts that same 'scale colocation' MW as colo — so the segment axis and geo axis book the same capacity to different segments",
    "refs": [
     "digest:seg-mix#c13",
     "digest:geo-region-denominator#c7",
     "digest:geo-region-denominator#c9"
    ]
   },
   {
    "step": "model-impact",
    "text": "seg.hyperscale 0.44 overstates CE hyperscale-owned demand and understates the colo-operator cell; the venture's implied DE×hyperscale×large-operator beachhead is materially smaller, and the real buyers need colo-grade product (billing metering, multi-tenant DCIM), not hyperscale custom builds",
    "refs": [
     "ledger:seg.hyperscale",
     "ledger:seg.colocation",
     "profile:Who is the primary buyer you'll sell through first?"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Hyperscale self-build MW announced/operational by country",
    "where": "CBRE quarterly 'Europe Data Centres Figures'; hyperscaler capex-call site announcements for DE/PL/AT",
    "threshold": "CE-7 self-build share of Europe rising above ~25% would weaken the risk; staying ≤20% confirms it",
    "updates": "decreases"
   },
   {
    "signal": "Publication of a Europe-scoped hyperscale/colo/enterprise capacity split",
    "where": "Synergy Research Europe releases; EUDCA State of European Data Centres",
    "threshold": "Europe hyperscale-owned share reported <35%",
    "updates": "increases"
   }
  ],
  "judgeTotal": 18
 }
]

Every riskId must appear in exactly one group (as keepId or inside absorbs).
Emit JSON: { rationale, groups: [{keepId, absorbs: [true-duplicate riskIds, [] if none], foldedIndicators: []}] }
